#include <omp.h>
#include <stdio.h>
#include <stdlib.h>

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

extern int omp_num_threads;

static void lud_diagonal(float *m, int matrix_dim, int offset)
{
    int i, j, k;
    float shadow[BLOCK_SIZE][BLOCK_SIZE];

    /* Load the diagonal block into shadow */
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            shadow[i][j] = m[(offset + i) * matrix_dim + offset + j];
        }
    }

    /* Perform LU decomposition on the diagonal block */
    for (i = 0; i < BLOCK_SIZE; i++) {
        /* Update column i (L part) */
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            for (k = 0; k < i; k++) {
                shadow[j][i] -= shadow[j][k] * shadow[k][i];
            }
            shadow[j][i] /= shadow[i][i];
        }
        /* Update row i (U part) */
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            for (k = 0; k < i + 1; k++) {
                shadow[i + 1 > BLOCK_SIZE - 1 ? BLOCK_SIZE - 1 : i][j] -= 0; /* placeholder */
            }
        }
        /* Actually update U rows */
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            for (k = 0; k < i + 1; k++) {
                shadow[i+1 <= BLOCK_SIZE-1 ? i+1 : i][j] -= 0;
            }
        }
    }

    /* Write back */
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[(offset + i) * matrix_dim + offset + j] = shadow[i][j];
        }
    }
}

/* Reimplement diagonal correctly matching the CUDA kernel logic */
static void lud_diagonal_correct(float *m, int matrix_dim, int offset)
{
    int i, j, k;
    float shadow[BLOCK_SIZE][BLOCK_SIZE];

    /* Load block */
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            shadow[i][j] = m[(offset + i) * matrix_dim + offset + j];
        }
    }

    /* The CUDA kernel iterates i from 0 to BLOCK_SIZE-2:
       For each i:
         - threads with threadIdx.x > i update column i:
           shadow[threadIdx.x][i] -= sum_{j=0}^{i-1} shadow[threadIdx.x][j]*shadow[j][i]
           shadow[threadIdx.x][i] /= shadow[i][i]
         - then threads with threadIdx.x > i update row i+1:
           shadow[i+1][threadIdx.x] -= sum_{j=0}^{i} shadow[i+1][j]*shadow[j][threadIdx.x]
    */
    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        /* Update column i for rows > i (L factor) */
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            float sum = shadow[j][i];
            for (k = 0; k < i; k++) {
                sum -= shadow[j][k] * shadow[k][i];
            }
            shadow[j][i] = sum / shadow[i][i];
        }
        /* Update row i+1 for columns > i (U factor) */
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            float sum = shadow[i+1][j];
            for (k = 0; k < i + 1; k++) {
                sum -= shadow[i+1][k] * shadow[k][j];
            }
            shadow[i+1][j] = sum;
        }
    }

    /* Write back */
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[(offset + i) * matrix_dim + offset + j] = shadow[i][j];
        }
    }
}

static void lud_perimeter_omp(float *m, int matrix_dim, int offset)
{
    int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;
    int b, i, j, k;

    #pragma omp parallel for num_threads(omp_num_threads) private(i, j, k)
    for (b = 0; b < num_blocks; b++) {
        float dia[BLOCK_SIZE][BLOCK_SIZE];
        float peri_row[BLOCK_SIZE][BLOCK_SIZE];
        float peri_col[BLOCK_SIZE][BLOCK_SIZE];

        /* Load diagonal block */
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                dia[i][j] = m[(offset + i) * matrix_dim + offset + j];
            }
        }

        /* Load peri_row block: row block b+1 */
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                peri_row[i][j] = m[(offset + i) * matrix_dim + offset + (b+1)*BLOCK_SIZE + j];
            }
        }

        /* Load peri_col block: col block b+1 */
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                peri_col[i][j] = m[(offset + (b+1)*BLOCK_SIZE + i) * matrix_dim + offset + j];
            }
        }

        /* Update peri_row using dia (L factor applied to rows) */
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                for (k = 0; k < i; k++) {
                    peri_row[i][j] -= dia[i][k] * peri_row[k][j];
                }
            }
        }

        /* Update peri_col using dia (U factor applied to columns) */
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                for (k = 0; k < j; k++) {
                    peri_col[i][j] -= peri_col[i][k] * dia[k][j];
                }
                peri_col[i][j] /= dia[j][j];
            }
        }

        /* Write back peri_row (rows 1..BLOCK_SIZE-1) */
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                m[(offset + i) * matrix_dim + offset + (b+1)*BLOCK_SIZE + j] = peri_row[i][j];
            }
        }

        /* Write back peri_col */
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                m[(offset + (b+1)*BLOCK_SIZE + i) * matrix_dim + offset + j] = peri_col[i][j];
            }
        }
    }
}

static void lud_internal_omp(float *m, int matrix_dim, int offset)
{
    int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;
    int by, bx;

    #pragma omp parallel for num_threads(omp_num_threads) collapse(2) private(bx)
    for (by = 0; by < num_blocks; by++) {
        for (bx = 0; bx < num_blocks; bx++) {
            int global_row_id = offset + (by + 1) * BLOCK_SIZE;
            int global_col_id = offset + (bx + 1) * BLOCK_SIZE;
            float peri_row[BLOCK_SIZE][BLOCK_SIZE];
            float peri_col[BLOCK_SIZE][BLOCK_SIZE];
            int i, j, k;
            float sum;

            /* Load peri_row: the row strip at offset rows, global_col_id cols */
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    peri_row[i][j] = m[(offset + i) * matrix_dim + global_col_id + j];
                }
            }

            /* Load peri_col: the col strip at global_row_id rows, offset cols */
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    peri_col[i][j] = m[(global_row_id + i) * matrix_dim + offset + j];
                }
            }

            /* Update internal block */
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    sum = 0;
                    for (k = 0; k < BLOCK_SIZE; k++) {
                        sum += peri_col[i][k] * peri_row[k][j];
                    }
                    m[(global_row_id + i) * matrix_dim + global_col_id + j] -= sum;
                }
            }
        }
    }
}

void lud_omp(float *m, int matrix_dim)
{
    int i;
    for (i = 0; matrix_dim - BLOCK_SIZE > i; i += BLOCK_SIZE) {
        lud_diagonal_correct(m, matrix_dim, i);
        lud_perimeter_omp(m, matrix_dim, i);
        lud_internal_omp(m, matrix_dim, i);
    }
    lud_diagonal_correct(m, matrix_dim, i);
}
